import{_ as e,c as t,o,a as d}from"./app.2dc46da8.js";const r='{"title":"Note","description":"","frontmatter":{},"headers":[{"level":2,"title":"TypeScript Support","slug":"typescript-support"},{"level":3,"title":"TypeScript 编译器选项","slug":"typescript-编译器选项"}],"relativePath":"docs/vite/note.md"}',c={},p=[d('<h1 id="note" tabindex="-1">Note <a class="header-anchor" href="#note" aria-hidden="true">#</a></h1><h2 id="typescript-support" tabindex="-1">TypeScript Support <a class="header-anchor" href="#typescript-support" aria-hidden="true">#</a></h2><p>Vite 天然支持引入 <code>.ts</code> 文件</p><p>Vite 仅执行 <code>.ts</code> 文件的转译工作，并 <strong>不</strong> 执行任何类型检查</p><p>所以如果由类型使用错误的代码，只能在打包后运行的时候才会报错</p><p>Vite使用 <strong>esbuild</strong> 将 TypeScript 转换为 JavaScript，这比普通 <code>tsc</code> 快20到30倍，并且 HMR 更新可以在50毫秒内反映在浏览器中</p><blockquote><p>所以你会在相应项目的devDependencies中看到<code>vue-tsc</code><code>vue-tsc</code> is a <em>Type-check and dts build command line tool</em></p></blockquote><h3 id="typescript-编译器选项" tabindex="-1">TypeScript 编译器选项 <a class="header-anchor" href="#typescript-编译器选项" aria-hidden="true">#</a></h3><p><code>tsconfig.json</code> 中 <code>compilerOptions</code> 下的一些配置项需要特别注意</p><h4 id="isolatedmodules" tabindex="-1"><code>isolatedModules</code> <a class="header-anchor" href="#isolatedmodules" aria-hidden="true">#</a></h4><p>应该设置为 <code>true</code></p><p>然而，一些库（如：<a href="https://github.com/vuejs/core/issues/1228" target="_blank" rel="noopener noreferrer"><code>vue</code></a>）不能很好地与 <code>&quot;isolatedModules&quot;: true</code> 共同工作。你可以在上游仓库修复好之前暂时使用 <code>&quot;skipLibCheck&quot;: true</code> 来缓解这个错误</p>',12)];var a=e(c,[["render",function(e,d,r,c,a,s){return o(),t("div",null,p)}]]);export{r as __pageData,a as default};
